import React, { useState, useEffect, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Trash2, Edit, ArrowLeft, Package, X, Save, 
  Loader2, Search, TrendingDown, AlertCircle, CheckCircle2, 
  Box, Calendar, Tag, Layers 
} from 'lucide-react';

// IMPORTANTE: Usamos el nuevo componente de pegado rápido
import GestionInventario from './GestionInventario'; 
import { generarNombreImagen } from '../utils/helpers';

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();
  const [ofertas, setOfertas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showManual, setShowManual] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  
  const [nuevoProd, setNuevoProd] = useState({
    tipo: '', marca: '', contenido: '', categoria: 'Almacén',
    precioNuevo: '', precioViejo: '', stock: '', fechaVencimiento: ''
  });

  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  useEffect(() => { 
    if(localId) cargarOfertas(); 
  }, [localId]);

  const cargarOfertas = async () => {
    setLoading(true);
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setOfertas(res.data);
    } catch (e) { 
      console.error("Error cargando ofertas:", e); 
    }
    setLoading(false);
  };

  const ofertasFiltradas = useMemo(() => {
    return ofertas.filter(o => 
      o.producto.toLowerCase().includes(searchTerm.toLowerCase()) ||
      o.categoria.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [ofertas, searchTerm]);

  const stats = useMemo(() => ({
    total: ofertas.length,
    sinStock: ofertas.filter(o => o.stock <= 0).length,
    enOferta: ofertas.filter(o => Number(o.precioViejo) > Number(o.precioNuevo)).length
  }), [ofertas]);

  const handleCargaManual = async (e) => {
    e.preventDefault();
    try {
      const item = {
        ...nuevoProd,
        producto: `${nuevoProd.tipo} ${nuevoProd.marca} ${nuevoProd.contenido}`.trim(),
        publicId: generarNombreImagen(nuevoProd.tipo, nuevoProd.marca, nuevoProd.contenido),
        local: localId,
        precioNuevo: Number(nuevoProd.precioNuevo),
        precioViejo: Number(nuevoProd.precioViejo) || Number(nuevoProd.precioNuevo),
        stock: Number(nuevoProd.stock) || 0
      };
      
      await axios.post(`${API_URL}/api/ofertas`, item);
      setShowManual(false);
      setNuevoProd({ tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: '', fechaVencimiento: '' });
      cargarOfertas();
    } catch (err) { 
      alert("Error al guardar el producto manual"); 
    }
  };

  return (
    <div style={containerStyle}>
      {/* Barra Superior */}
      <div style={topBar}>
        <button onClick={() => navigate('/dashboard')} style={btnBack}>
          <ArrowLeft size={18}/> Volver al Dashboard
        </button>
        <div style={badgeLocal}>ID Local: {localId?.slice(-6)}</div>
      </div>

      {/* Título y Acción Principal */}
      <div style={headerStyle}>
        <div>
          <h1 style={titleStyle}>Panel de Inventario</h1>
          <p style={subtitleStyle}>Gestiona tus productos y ofertas en tiempo real</p>
        </div>
        <button onClick={() => setShowManual(true)} style={btnPlus}>
          <Plus size={20}/> Nuevo Producto Manual
        </button>
      </div>

      {/* Indicadores Rápidos (Stats) */}
      <div style={statsGrid}>
        <div style={statCard}>
          <Box color="#3b82f6" />
          <div><span style={statNum}>{stats.total}</span><p style={statLabel}>Total Productos</p></div>
        </div>
        <div style={{...statCard, borderLeft: '4px solid #ef4444'}}>
          <AlertCircle color="#ef4444" />
          <div><span style={statNum}>{stats.sinStock}</span><p style={statLabel}>Sin Stock</p></div>
        </div>
        <div style={{...statCard, borderLeft: '4px solid #10b981'}}>
          <TrendingDown color="#10b981" />
          <div><span style={statNum}>{stats.enOferta}</span><p style={statLabel}>En Oferta</p></div>
        </div>
      </div>

      {/* COMPONENTE DE CARGA RÁPIDA (PEGADO DESDE EXCEL) */}
      <GestionInventario localId={localId} onComplete={cargarOfertas} />

      {/* Buscador */}
      <div style={searchBarContainer}>
        <Search size={20} color="#94a3b8" style={searchIcon} />
        <input 
          style={searchInput} 
          placeholder="Buscar por nombre, marca o categoría..." 
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      {/* Listado de Productos */}
      <div style={gridStyle}>
        {loading ? (
          <div style={loaderContainer}><Loader2 className="animate-spin" size={40} color="#e67e22"/></div>
        ) : ofertasFiltradas.length > 0 ? (
          ofertasFiltradas.map(o => (
            <div key={o._id} style={{...itemCard, borderTop: o.stock <= 0 ? '4px solid #ef4444' : '1px solid #f1f5f9'}}>
              <div style={cardHeader}>
                <div style={o.stock <= 0 ? badgeStockOut : badgeStockIn}>
                   {o.stock <= 0 ? 'AGOTADO' : `Stock: ${o.stock}`}
                </div>
                {Number(o.precioViejo) > Number(o.precioNuevo) && <div style={badgePromo}>Oferta</div>}
              </div>

              <div style={cardBody}>
                <h4 style={prodName}>{o.producto}</h4>
                <div style={categoryTag}><Layers size={12}/> {o.categoria}</div>
                
                <div style={priceContainer}>
                  <span style={currentPrice}>${o.precioNuevo}</span>
                  {o.precioViejo > o.precioNuevo && <span style={oldPrice}>${o.precioViejo}</span>}
                </div>
              </div>

              <div style={cardFooter}>
                <button style={btnActionEdit} title="Editar"><Edit size={16}/></button>
                <button 
                  style={btnActionDelete} 
                  title="Eliminar"
                  onClick={async () => {
                    if(window.confirm(`¿Eliminar ${o.producto}?`)) {
                      await axios.delete(`${API_URL}/api/ofertas/${o._id}`);
                      cargarOfertas();
                    }
                  }}
                ><Trash2 size={16}/></button>
              </div>
            </div>
          ))
        ) : (
          <div style={emptyState}>
            <Package size={60} color="#e2e8f0" />
            <p>No hay productos que coincidan con la búsqueda</p>
          </div>
        )}
      </div>

      {/* MODAL DE CARGA MANUAL */}
      {showManual && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <h3 style={{margin:0}}>Registrar Producto</h3>
              <button onClick={() => setShowManual(false)} style={closeBtn}><X/></button>
            </div>
            <form onSubmit={handleCargaManual} style={formStyle}>
              <div style={inputRow}>
                <div style={inputGroup}>
                  <label style={labelS}><Tag size={14}/> Tipo</label>
                  <input style={inputS} placeholder="Ej: Arroz" onChange={e => setNuevoProd({...nuevoProd, tipo: e.target.value})} required />
                </div>
                <div style={inputGroup}>
                  <label style={labelS}><CheckCircle2 size={14}/> Marca</label>
                  <input style={inputS} placeholder="Ej: Lucchetti" onChange={e => setNuevoProd({...nuevoProd, marca: e.target.value})} required />
                </div>
              </div>
              <div style={inputGroup}>
                <label style={labelS}><Layers size={14}/> Contenido (Peso/Vol)</label>
                <input style={inputS} placeholder="Ej: 1kg" onChange={e => setNuevoProd({...nuevoProd, contenido: e.target.value})} required />
              </div>
              <div style={inputRow}>
                <div style={inputGroup}>
                  <label style={labelS}>Precio Hoy</label>
                  <input style={inputS} type="number" placeholder="$0" onChange={e => setNuevoProd({...nuevoProd, precioNuevo: e.target.value})} required />
                </div>
                <div style={inputGroup}>
                  <label style={labelS}>Stock</label>
                  <input style={inputS} type="number" placeholder="Cant." onChange={e => setNuevoProd({...nuevoProd, stock: e.target.value})} required />
                </div>
              </div>
              <button type="submit" style={btnSave}><Save size={18}/> Guardar en Base de Datos</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

// --- DISEÑO DE INTERFAZ (CSS-in-JS) ---
const containerStyle = { padding: '40px', maxWidth: '1200px', margin: '0 auto', fontFamily: '"Inter", sans-serif', color: '#1e293b' };
const topBar = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' };
const badgeLocal = { background: '#f1f5f9', padding: '6px 15px', borderRadius: '20px', fontSize: '0.8rem', color: '#64748b', fontWeight: '700' };
