const statCard = { background: 'white', padding: '24px', borderRadius: '20px', display: 'flex', alignItems: 'center', gap: '20px', boxShadow: '0 4px 15px -3px rgba(0,0,0,0.04)', border: '1px solid #f1f5f9' };
const statNum = { fontSize: '1.8rem', fontWeight: '900', display: 'block', color: '#0f172a' };
const statLabel = { margin: 0, fontSize: '0.9rem', color: '#64748b', fontWeight: '600' };
const searchBarContainer = { position: 'relative', marginBottom: '30px' };
